mapper.select:
SELECT ID, WORKPLACE_ID, USER_ID, DAY_OF_WEEK, SCHEDULED_CHECK_IN_TIME, SCHEDULED_CHECK_OUT_TIME
FROM WORKPLACE_MEMBER_SCHEDULES
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
ORDER BY DAY_OF_WEEK

mapper.delete:
DELETE FROM WORKPLACE_MEMBER_SCHEDULES
WHERE WORKPLACE_ID = #{workplaceId}
  AND USER_ID = #{userId}
